=<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Asistente Interno | Enviar Petición</title>
    <link href="https://googleapis.com" rel="stylesheet">
    <style>
        :root {
            --primary: #6366f1;
            --primary-hover: #4f46e5;
            --bg: #f8fafc;
            --card-bg: #ffffff;
            --text: #1e293b;
        }

        body {
            font-family: 'Inter', sans-serif;
            background-color: var(--bg);
            background-image: radial-gradient(circle at top right, #e0e7ff, transparent),
                              radial-gradient(circle at bottom left, #f1f5f9, transparent);
            height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            margin: 0;
        }

        .container {
            background: var(--card-bg);
            padding: 2.5rem;
            border-radius: 20px;
            box-shadow: 0 10px 25px rgba(0, 0, 0, 0.05);
            width: 100%;
            max-width: 400px;
            border: 1px solid rgba(255, 255, 255, 0.3);
        }

        h2 {
            margin-top: 0;
            color: var(--text);
            font-weight: 600;
            text-align: center;
            font-size: 1.5rem;
            margin-bottom: 1.5rem;
        }

        .form-group {
            margin-bottom: 1.2rem;
        }

        label {
            display: block;
            margin-bottom: 0.5rem;
            font-size: 0.875rem;
            font-weight: 600;
            color: #64748b;
        }

        input, textarea {
            width: 100%;
            padding: 0.75rem;
            border: 1.5px solid #e2e8f0;
            border-radius: 10px;
            box-sizing: border-box;
            font-size: 1rem;
            transition: all 0.3s ease;
            outline: none;
            background-color: #fcfcfc;
        }

        input:focus, textarea:focus {
            border-color: var(--primary);
            box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.1);
        }

        textarea {
            resize: none;
            height: 100px;
        }

        button {
            width: 100%;
            padding: 0.8rem;
            background-color: var(--primary);
            color: white;
            border: none;
            border-radius: 10px;
            font-size: 1rem;
            font-weight: 600;
            cursor: pointer;
            transition: background 0.3s ease, transform 0.2s ease;
            margin-top: 1rem;
        }

        button:hover {
            background-color: var(--primary-hover);
            transform: translateY(-1px);
        }

        button:active {
            transform: translateY(0);
        }

        #status {
            margin-top: 1rem;
            text-align: center;
            font-size: 0.875rem;
            padding: 0.75rem;
            border-radius: 8px;
            display: none;
        }

        .success { background: #dcfce7; color: #166534; display: block !important; }
        .error { background: #fee2e2; color: #991b1b; display: block !important; }
    </style>
</head>
<body>

<div class="container">
    <h2>🚀 Nueva Petición</h2>
    <form id="peticionForm">
        <div class="form-group">
            <label for="usuario">Nombre de Usuario</label>
            <input type="text" id="usuario" name="usuario" placeholder="Ej: Juan Pérez" required>
        </div>
        <div class="form-group">
            <label for="mensaje">Tu Mensaje</label>
            <textarea id="mensaje" name="mensaje" placeholder="¿En qué podemos ayudarte?" required></textarea>
        </div>
        <button type="submit" id="btnEnviar">Enviar a n8n</button>
    </form>
    <div id="status"></div>
</div>

<script>
    const form = document.getElementById('peticionForm');
    const statusDiv = document.getElementById('status');
    const btn = document.getElementById('btnEnviar');

    form.addEventListener('submit', async (e) => {
        e.preventDefault();

        const data = {
            usuario: document.getElementById('usuario').value,
            mensaje: document.getElementById('mensaje').value
        };

        btn.innerText = 'Enviando...';
        btn.disabled = true;

        try {
            const response = await fetch('https://lilseniorj.app.n8n.cloud/webhook/asistente-interno', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(data)
            });

            if (response.ok) {
                statusDiv.textContent = '¡Enviado con éxito! 🎉';
                statusDiv.className = 'success';
                form.reset();
            } else {
                throw new Error();
            }
        } catch (error) {
            statusDiv.textContent = 'Error al enviar. Verifica tu n8n.';
            statusDiv.className = 'error';
        } finally {
            btn.innerText = 'Enviar a n8n';
            btn.disabled = false;
        }
    });
</script>

</body>
</html>

